INSERT INTO fact_membership (university_id, conference_id, membership_type_id, joined_year, left_year, sport_id, division_id) SELECT (SELECT university_id FROM dim_universities WHERE LOWER(current_university_name) = LOWER('southern methodist university')), (SELECT conference_id FROM dim_conferences WHERE LOWER(current_conference_name) = LOWER('western athletic conference')), (SELECT membership_type_id FROM dim_membership_types WHERE LOWER(type_name) = LOWER('Full Member')), 1996, 2005, NULL, (SELECT division_id FROM dim_divisions WHERE LOWER(division_name) = LOWER('ncaa division i')) WHERE (SELECT university_id FROM dim_universities WHERE LOWER(current_university_name) = LOWER('southern methodist university')) IS NOT NULL AND (SELECT conference_id FROM dim_conferences WHERE LOWER(current_conference_name) = LOWER('western athletic conference')) IS NOT NULL AND (SELECT membership_type_id FROM dim_membership_types WHERE LOWER(type_name) = LOWER('Full Member')) IS NOT NULL AND (SELECT division_id FROM dim_divisions WHERE LOWER(division_name) = LOWER('ncaa division i')) IS NOT NULL ON CONFLICT DO NOTHING;
